### nodejs
```js 

const puppeteer = require(&#39;puppeteer-extra&#39;);
const protobuf = require(&#39;protobufjs&#39;);
const stealthPlugin = require(&#39;puppeteer-extra-plugin-stealth&#39;);
const zlib = require(&#39;zlib&#39;);

var protoPath = __dirname + &#34;/douyinLive.proto&#34;;
var baseUrl = &#34;https://live.douyin.com/&#34;;

class douyinDanmakuPage {
    constructor(roomId) {
        this.roomId = roomId;
        this.url = baseUrl + roomId;
        this.browser = null;
        this.giftGroupMap = {};
        this.onConnectSuccess = null;
        this.onMessage = null;
        this.protoRoot = null;
    }
    openPage() {
        try {
            puppeteer.use(stealthPlugin());
            protobuf.load(protoPath, (err, root) =&gt; {
                if (err)
                    throw err;
                this.protoRoot = root;
                this.puppeteerLaunch(this.url, true);
            });
        } catch (e) {
            console.error(e);
        }
    }
    refreshPage() {
        try {
            this.closePage();
            this.openPage();
        } catch (e) {
            console.error(e);
        }
    }
    closePage() {
        this.browser &amp;&amp; this.browser.close();
    }
    puppeteerLaunch(url, isheadless) {
        try {
            puppeteer.launch({
                headless: isheadless,
                ignoreHTTPSErrors: true,
            }).then(async bs =&gt; {
                this.browser = bs;
                let page = await this.browser.newPage();
                // 创建 CDP 对象
                const client = await page.target().createCDPSession();
                // 打开网络跟踪，允许网络事件通知到浏览器
                await client.send(&#39;Network.enable&#39;);
                console.log(&#34;抖音尝试连接:&#34;, url);
                await page.goto(url, {
                    timeout: 0
                });
                await page.setCacheEnabled(false);
                //旧版http消息解析
                page.on(&#39;response&#39;, rep =&gt; this.onLogResponse.call(this, rep));
                //新版websocket消息解析
                client.on(&#39;Network.webSocketFrameReceived&#39;, msg =&gt; this.onWebsocketFrameReceived.call(this, msg));
                page.on(&#39;close&#39;, this.onClosePage);
                page.on(&#39;error&#39;, this.onErrorPage);
                console.log(&#34;抖音连接成功:&#34;, url);
                this.onConnectSuccess &amp;&amp; this.onConnectSuccess(this.roomId);
            });
        } catch (e) {
            console.error(e);
        }
    }
    onWebsocketFrameReceived(msg) {
        try {
            var data = msg.response.payloadData;
            var buffer = new Buffer.from(data, &#34;base64&#34;);
            var protoWebcastMessage = this.protoRoot.lookupType(&#34;douyinLive.PushFrame&#34;);
            var msg = protoWebcastMessage.decode(buffer);
            if (msg.HeadersList &amp;&amp; msg.HeadersList.length &gt; 0) {
                for (var i = 0; i &lt; msg.HeadersList.length; i++) {
                    var val = msg.HeadersList[i];
                    var key = val.Key;
                    var value = val.Value;
                    if (key == &#34;compress_type&#34; &amp;&amp; value == &#34;gzip&#34;) {
                        zlib.gunzip(msg.Payload, (err, decoded) =&gt; this.doGunzip.call(this, err, decoded));
                        break;
                    }
                }
            }
        } catch (e) {
            console.error(e);
        }
    }
    doGunzip(err, decoded) {
        if (err) {
            console.error(err);
            return;
        }
        this.decodeBuffer(decoded);
    }
    onLogResponse(response) {
        if (response.status() != 200)
            return;
        var request = response.request();
        if (request.url().indexOf(&#39;_signature=&#39;) != -1
            &amp;&amp; response.headers()[&#34;content-type&#34;].indexOf(&#34;application/protobuffer&#34;) != -1) {
            response.buffer().then(buffer =&gt; this.decodeBuffer.call(this, buffer));
        }
    }
    onClosePage() {
        console.log(&#34;页面关闭&#34;);
    }
    onErrorPage() {
        console.log(&#34;页面崩溃&#34;);
    }
    //#region Proto解析相关
    decodeBuffer(buffer) {
        try {
            var protoWebcastMessage = this.protoRoot.lookupType(&#34;douyinLive.WebcastMessage&#34;);
            var webcastMessage = protoWebcastMessage.decode(buffer);
            if (!webcastMessage.messages)
                return;
            webcastMessage.messages.forEach(msg =&gt; {
                if (msg.payload.length &gt; 0) {
                    var msgJson = {};
                    msgJson.method = msg.method;
                    var jsonData;
                    switch (msg.method) {
                        case &#34;WebcastChatMessage&#34;:
                            jsonData = this.getChatJson(msg.payload);
                            break;
                        case &#34;WebcastGiftMessage&#34;:
                            jsonData = this.getGiftJson(msg.payload);
                            break;
                        case &#34;WebcastMemberMessage&#34;:
                            jsonData = this.getMemberJson(msg.payload);
                            break;
                        default:
                            break;
                    }
                    if (jsonData) {
                        msgJson.jsonData = jsonData;
                        this.onMessage &amp;&amp; this.onMessage(JSON.stringify(msgJson));
                        // console.log(JSON.stringify(msgJson));
                    }
                }
            })
        } catch (e) {
            console.error(e);
        }
    }
    getChatJson(buffer) {
        var protoChat = this.protoRoot.lookupType(&#34;douyinLive.ChatMessage&#34;);
        var msg = protoChat.decode(buffer);
        var json = JSON.stringify(msg);
        msg = JSON.parse(json);
        console.log(&#39;\x1b[0m&#39;, msg.user.nickname, &#34;: &#34;, msg.content);
        return JSON.stringify(msg);
    }
    getGiftJson(buffer) {
        var protoGift = this.protoRoot.lookupType(&#34;douyinLive.GiftMessage&#34;);
        var msg = protoGift.decode(buffer);
        var json = JSON.stringify(msg);
        msg = JSON.parse(json);
        var groupId = msg.groupId;
        var sendCnt;
        var preSendCnt = this.giftGroupMap[groupId];
        if (!preSendCnt) {
            sendCnt = msg.repeatCount;
        } else {
            sendCnt = msg.repeatCount &lt;= preSendCnt ? msg.repeatCount : (msg.repeatCount - preSendCnt);
        }
        this.giftGroupMap[groupId] = sendCnt;
        msg.sendCnt = sendCnt;
        if (!msg.gift) {
            console.log(&#39;\x1b[32m&#39;, `${msg.user.nickname} 送出GiftId:${msg.giftId} x${sendCnt}`);
        }
        else {
            if (!msg.gift.diamondCount) {
                msg.gift.diamondCount = 0;
            }
            console.log(&#39;\x1b[32m&#39;, `${msg.user.nickname} 送出${msg.gift.name} x${sendCnt}`);
        }
        return JSON.stringify(msg);
    }
    getMemberJson(buffer) {
        var protoMember = this.protoRoot.lookupType(&#34;douyinLive.MemberMessage&#34;);
        var msg = protoMember.decode(buffer);
        var json = JSON.stringify(msg);
        msg = JSON.parse(json);
        console.log(&#39;\x1b[0m&#39;, msg.user.nickname, &#34;进入房间&#34;);
        return JSON.stringify(msg);
    }
    //#endregion
}

```
--&gt;
&lt;h1 id=&#34;进制转换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#进制转换&#34;&gt;#&lt;/a&gt; 进制转换&lt;/h1&gt;
&lt;h2 id=&#34;10进制转换为n个字节的16进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#10进制转换为n个字节的16进制&#34;&gt;#&lt;/a&gt; 10 进制转换为 N 个字节的 16 进制&lt;/h2&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2378&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; lenArr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;a&lt;span class=&#34;token operator&#34;&gt;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;n&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0xFF&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;a&lt;span class=&#34;token operator&#34;&gt;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;8&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;n&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0xFF&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;...&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;a&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0xFF&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;git账号清空&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git账号清空&#34;&gt;#&lt;/a&gt; Git 账号清空&lt;/h1&gt;
&lt;p&gt;设置清空 git 保存的账号密码并每次操作时强制输入账号密码，即 git 不自定保存账号密码&lt;/p&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git config --system --unset credential.helper&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;git自动保存输入的账号密码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git自动保存输入的账号密码&#34;&gt;#&lt;/a&gt; Git 自动保存输入的账号密码&lt;/h1&gt;
&lt;p&gt;设置 git 自动保存输入的账号密码&lt;/p&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git config --global credential.helper store&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;ssh密钥生成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ssh密钥生成&#34;&gt;#&lt;/a&gt; SSH 密钥生成&lt;/h1&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ssh-keygen  -t rsa  -C &lt;span class=&#34;token string&#34;&gt;&#34;邮箱&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;tortoisegit-设置ssh方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tortoisegit-设置ssh方式&#34;&gt;#&lt;/a&gt; TortoiseGit 设置 ssh 方式&lt;/h1&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vd3ViYWl3YW4vcC8xMTMwNDE0Ny5odG1s&#34;&gt;参考链接&lt;/span&gt;&lt;br /&gt;
 1. 打开小乌龟内置工具 PuTTY Key Generator 生成秘钥&lt;br /&gt;
&lt;img data-src=&#34;https://shioho-public.oss-cn-hangzhou.aliyuncs.com/git/shoka-git-about/1.png&#34; alt=&#34;&#34; /&gt;&lt;br /&gt;
 2. 保存秘钥至本地&lt;br /&gt;
&lt;img data-src=&#34;https://shioho-public.oss-cn-hangzhou.aliyuncs.com/git/shoka-git-about/2.png&#34; alt=&#34;&#34; /&gt;&lt;br /&gt;
 3. 打开 Pageant 工具，添加密钥文件&lt;br /&gt;
&lt;img data-src=&#34;https://shioho-public.oss-cn-hangzhou.aliyuncs.com/git/shoka-git-about/3.png&#34; alt=&#34;&#34; /&gt;&lt;br /&gt;
 4. 添加公钥到账号&lt;br /&gt;
&lt;img data-src=&#34;https://shioho-public.oss-cn-hangzhou.aliyuncs.com/git/shoka-git-about/4.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;tortoisegit-pageant开机自启动且加载ssh-key&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tortoisegit-pageant开机自启动且加载ssh-key&#34;&gt;#&lt;/a&gt; TortoiseGit Pageant 开机自启动且加载 SSH Key&lt;/h1&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzQxMTk0NTM0L2FydGljbGUvZGV0YWlscy84NjQ3ODYyNw==&#34;&gt;参考链接&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;1. 首先找到 TortoiseGit 的安装目录的 bin 目录，然后找到 pageant.exe 运行 或是 window 键打开开始菜单，搜索 pageant 右键打开文件夹所在位置创建并复制快捷方式&lt;br /&gt;
&lt;img data-src=&#34;https://shioho-public.oss-cn-hangzhou.aliyuncs.com/git/shoka-git-about/5.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;p&gt;2.window+r 输入 shell:startup; 点击确定将复制好的快捷方式放入该目录下&lt;br /&gt;
&lt;img data-src=&#34;https://shioho-public.oss-cn-hangzhou.aliyuncs.com/git/shoka-git-about/6.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;p&gt;3. 右键属性中找到快捷方式在目标后面拼上 ppk 文件的目录 (空格 + 文件路径)&lt;br /&gt;
&lt;img data-src=&#34;https://shioho-public.oss-cn-hangzhou.aliyuncs.com/git/shoka-git-about/7.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;git-help-gc错误解决方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git-help-gc错误解决方法&#34;&gt;#&lt;/a&gt; &#39;git help gc&#39; 错误解决方法&lt;/h1&gt;
&lt;p&gt;&lt;code&gt;git help gc错误解决方法，有两种方式,推荐第一种方式。&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;1，在当下工程，使用「Git Bash Here」执行下面命令&lt;/p&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;$ git fsck&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;$ git gc&lt;span class=&#34;token parameter&#34;&gt; --prune&lt;/span&gt;=now&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;2. 如果执行完上面的命令还是不行的话，可以尝试删掉.git\objects\pack 下的文件。重新 pull 就可以了。记得做好备份。&lt;/p&gt;
&lt;h1 id=&#34;git-还原本地提交的某个节点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git-还原本地提交的某个节点&#34;&gt;#&lt;/a&gt; git 还原本地提交的某个节点&lt;/h1&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;$ git reset 节点id  相对路径&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;git-查找不可访问文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git-查找不可访问文件&#34;&gt;#&lt;/a&gt; git 查找不可访问文件&lt;/h1&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git fsck --unreachable&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;恢复被删除的git-stash记录&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#恢复被删除的git-stash记录&#34;&gt;#&lt;/a&gt; 恢复被删除的 Git stash 记录&lt;/h1&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuamlhbnNodS5jb20vcC9hZTE5ODdlZmVjNjE=&#34;&gt;参考链接 1&lt;/span&gt;&lt;br /&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aHVhbmxhbi56aGlodS5jb20vcC8yODk0ODU2Nw==&#34;&gt; 参考链接 2&lt;/span&gt;&lt;/p&gt;
&lt;h1 id=&#34;git-查看工作现场&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#git-查看工作现场&#34;&gt;#&lt;/a&gt; git 查看工作现场&lt;/h1&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git cat-file -p +&amp;lt;sha&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;github-单文件突破100m限制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#github-单文件突破100m限制&#34;&gt;#&lt;/a&gt; github 单文件突破 100M 限制&lt;/h1&gt;
&lt;p&gt;1.windows 下安装 &lt;code&gt;lfs&lt;/code&gt;   &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXQtbGZzLmdpdGh1Yi5jb20v&#34;&gt;下载地址&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;2. 初始化本地项目 lfs&lt;/p&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git lfs install&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;3. 添加大文件路径&lt;/p&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git lfs track &lt;span class=&#34;token string&#34;&gt;&#34;*.exe&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;4. 生成配置文件&lt;/p&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git add .gitattributes&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;5. 推送即可 &lt;code&gt;（注意：要先推送.gitattributes文件后才可上传大文件）&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;github-上传缓存设置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#github-上传缓存设置&#34;&gt;#&lt;/a&gt; github 上传缓存设置&lt;/h1&gt;
&lt;figure class=&#34;highlight git&#34;&gt;&lt;figcaption data-lang=&#34;git&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;git config --global http.postBuffer 1048576000&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;矩阵&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#矩阵&#34;&gt;#&lt;/a&gt; 矩阵&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;复合变换可以通过矩阵串联获得，通常顺序为 &lt;code&gt;缩放、旋转、平移&lt;/code&gt; &lt;br /&gt;
矩阵的旋转顺序通常为 &lt;code&gt;zxy&lt;/code&gt; &lt;br /&gt;
Unity 内的模型和世界坐标系采用的都是 &lt;code&gt;左手坐标系&lt;/code&gt; ，摄像机坐标系采用的则是 &lt;code&gt;右手坐标系&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;缩放矩阵&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#缩放矩阵&#34;&gt;#&lt;/a&gt; 缩放矩阵&lt;/h2&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo fence=&#34;true&#34;&gt;[&lt;/mo&gt;&lt;mtable rowspacing=&#34;0.15999999999999992em&#34; columnspacing=&#34;1em&#34;&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mrow&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mrow&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mi&gt;y&lt;/mi&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mrow&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mi&gt;z&lt;/mi&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;false&#34;&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;mo fence=&#34;true&#34;&gt;]&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\begin{bmatrix}
kx&amp;amp;0&amp;amp;0&amp;amp;0\\
0&amp;amp;ky&amp;amp;0&amp;amp;0\\
