#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;g&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-1.8099999999999994em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.5500000000000007em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;arraycolsep&#34; style=&#34;width:0.5em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;arraycolsep&#34; style=&#34;width:0.5em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;col-align-c&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:2.05em;&#34;&gt;&lt;span style=&#34;top:-4.21em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.0099999999999993em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-1.8099999999999994em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.5500000000000007em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;&lt;span class=&#34;delimsizing mult&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:2.0510099999999998em;&#34;&gt;&lt;span style=&#34;top:-2.2500000000000004em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3.1550000000000002em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;delimsizinginner delim-size4&#34;&gt;&lt;span&gt;⎦&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-2.8099900000000004em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3.1550000000000002em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;delimsizinginner delim-size4&#34;&gt;&lt;span&gt;⎥&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-4.05101em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3.1550000000000002em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;delimsizinginner delim-size4&#34;&gt;&lt;span&gt;⎤&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.55002em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;Unity Shader 内置可用 &lt;code&gt;TANGENT_SPACE_ROTATION&lt;/code&gt;  宏直接获得矩阵&lt;/p&gt;
&lt;h1 id=&#34;标准光照模型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#标准光照模型&#34;&gt;#&lt;/a&gt; 标准光照模型&lt;/h1&gt;
&lt;h2 id=&#34;环境光&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#环境光&#34;&gt;#&lt;/a&gt; 环境光&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;通常为一个全局变量，可在 Window-&amp;gt;Lighting 中设置&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;自发光&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自发光&#34;&gt;#&lt;/a&gt; 自发光&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;通常使用该物体材质颜色，可自定义&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;漫反射&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#漫反射&#34;&gt;#&lt;/a&gt; 漫反射&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;兰伯特定律&lt;/strong&gt;&lt;br /&gt;
 &lt;code&gt;漫反射 = 光源颜色 * 材质的漫反射颜色 * max(0,dot(单位法线,指向光源的单位矢量))&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;半兰伯特模型&lt;/strong&gt;&lt;br /&gt;
 &lt;code&gt;漫反射 = 光源颜色 * 材质的漫反射颜色 * (0.5*dot(单位法线，指向光源的单位矢量)+0.5)&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;高光反射&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#高光反射&#34;&gt;#&lt;/a&gt; 高光反射&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;Phong 模型&lt;/strong&gt;&lt;br /&gt;
 &lt;code&gt;高光反射 = 光源颜色 * 材质的高光反射颜色 * pow(max(0,dot(指向观察摄像机的单位矢量，光源反射方向单位矢量))，材质光泽度)&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Blinn Phong 模型&lt;/strong&gt;&lt;br /&gt;
 &lt;code&gt;高光反射 = 光源颜色 * 材质的高光反射颜色 *  pow(max(0,dot(单位法线矢量，normalize(指向观察摄像机矢量+指向光源矢量))),材质光泽度)&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;uv采样&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#uv采样&#34;&gt;#&lt;/a&gt; UV 采样&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;Unity 内函数&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shader&#34;&gt;o.uv = TRANSFORM_TEX(data.texcoord,_MainTex);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;实现原理&lt;/strong&gt;&lt;br /&gt;
模型 UV*UV 缩放 + UV 偏移&lt;br /&gt;
 &lt;code&gt;o.uv = data.texcoord *_MainTex_ST.xy+_MainTex_ST.zw;&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;法线贴图纹理映射&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#法线贴图纹理映射&#34;&gt;#&lt;/a&gt; 法线贴图纹理映射&lt;/h1&gt;
&lt;p&gt;贴图像素值将法线由 [-1,1] 映射至 [0,1]&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-math&#34;&gt;pixel = \dfrac&amp;#123;normal+1&amp;#125;&amp;#123;2&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;获取法线纹理对应的法线向量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#获取法线纹理对应的法线向量&#34;&gt;#&lt;/a&gt; 获取法线纹理对应的法线向量&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;获取原理&lt;/strong&gt;&lt;br /&gt;
 &lt;code&gt;法线xy坐标&lt;/code&gt; 可经过贴图颜色采样 * 2-1 获得&lt;br /&gt;
由于法线是单位矢量，因此 &lt;code&gt;法线z值&lt;/code&gt; 可以由 xy 计算而得&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-math&#34;&gt;tangent.z = sqrt(1.0-saturate(dot(tangent.xy,tangent.xy)))
&lt;/code&gt;&lt;/pre&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;注意：当法线纹理设置 &lt;code&gt;为Normal Map&lt;/code&gt;  时，由于 Unity 会根据不同平台对纹理进行压缩，部分压缩格式，如 DXT5nm 会有不同的采样公式，因此建议直接使用 Unity 内置的 &lt;code&gt;UnpackNormal(tex2D(贴图，UV))&lt;/code&gt;  方法获取正确的法线位置&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;渐变纹理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#渐变纹理&#34;&gt;#&lt;/a&gt; 渐变纹理&lt;/h1&gt;
&lt;p&gt;使用半兰伯特值对渐变贴图进行纹理采样再乘以光照颜色和默认颜色得到漫反射颜色&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shader&#34;&gt;fixed halfLambert = 0.5*dot(worldNormal,worldLightDir)+0.5
fixed3 diffuse = tex2D(渐变纹理，fixed2(halfLambert,halfLambert)).xyz * 默认颜色 * 光照颜色
&lt;/code&gt;&lt;/pre&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;注意：需要把 Wrap Mode 设置为 Clamp，Repeat 模式下会将精度为 1.00001 的变为 0.00001，导致颜色变黑&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;遮罩纹理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#遮罩纹理&#34;&gt;#&lt;/a&gt; 遮罩纹理&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;遮罩纹理作用于对颜色分布的二次处理，可以使最终颜色更加细腻。例如某些模型表面需要暗一些，可以用较暗的颜色填充这一部分遮罩纹理贴图的某个通道，使最终效果颜色值与该通道相乘变小。总共有 rgba 四个通道可以使用，如高光反射区域放在 r 通道中，反射指数放在 b 通道中等。。。&lt;/p&gt;
&lt;/blockquote&gt;
